print('systemLog.verbosity:', opts.systemLog.verbosity);
print('operationProfiling.slowOpThresholdMs:', opts.operationProfiling.slowOpThresholdMs);
print('storage.wiredTiger.engineConfig.journalCompressor:', opts.storage.wiredTiger.engineConfig.journalCompressor);
print('security.keyFile:', opts.security.keyFile);
print('');
print('=== Replica Set Status ===');
rsStatus.members.forEach(m => print(m.name, '->', m.stateStr));
print('');
print('=== Live Runtime Parameters ===');
var logLevel = db.adminCommand({getParameter: '*'}).logLevel;
print('Live logLevel:', logLevel);
" 2>&1

# Verify data is available - write and read on primary (replica-2, state=1)
